<?php session_start(); require 'db.php'; require 'functions.php'; if(!isset($_SESSION['user_id'])) exit; $uid=$_SESSION['user_id']; $pid=$_POST['post_id']; $chk=$pdo->prepare("SELECT * FROM likes WHERE user_id=? AND post_id=?"); $chk->execute([$uid,$pid]); if($chk->fetch()){ $pdo->prepare("DELETE FROM likes WHERE user_id=? AND post_id=?")->execute([$uid,$pid]); $l=false; }else{ $pdo->prepare("INSERT INTO likes (user_id, post_id) VALUES (?,?)")->execute([$uid,$pid]); $l=true; $o=$pdo->prepare("SELECT user_id FROM posts WHERE id=?"); $o->execute([$pid]); createNotification($pdo,$o->fetchColumn(),$uid,'like_post',$pid); } $c=$pdo->prepare("SELECT COUNT(*) FROM likes WHERE post_id=?"); $c->execute([$pid]); echo json_encode(['success'=>true,'likes'=>$c->fetchColumn(),'liked'=>$l]); ?>
